#!/usr/bin/env node
import { readFile } from "node:fs/promises";
import { spawn } from "node:child_process";

function ignoreToGlob(ignoreText) {
  return ignoreText
    .split(/\r?\n/g)
    .map((x) => x.trim())
    .filter((x) => x && !x.startsWith("#"))
    .map((x) => {
      if (x.startsWith("!")) {
        if (x.startsWith("!/")) {
          return x;
        } else {
          return `!**/${x.slice(1)}`;
        }
      } else {
        if (x.startsWith("/")) {
          return x;
        } else {
          return `**/${x}`;
        }
      }
    })
    .flatMap((x) => {
      if (x.endsWith("/")) {
        return `${x}**`;
      } else {
        return [x, `${x}/**`];
      }
    });
}

